"use client"

import * as React from "react"

import { cn } from "@/lib/utils"

type StepState = "completed" | "active" | "pending"

type StepperContextValue = {
  activeStep: number
  orientation: "horizontal" | "vertical"
}

const StepperContext = React.createContext<StepperContextValue | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)

  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />")
  }

  return context
}

type StepperItemContextValue = {
  step: number
  state: StepState
}

const StepperItemContext = React.createContext<StepperItemContextValue | null>(
  null
)

function useStepperItem() {
  const context = React.useContext(StepperItemContext)

  if (!context) {
    throw new Error("useStepperItem must be used within a <StepperItem />")
  }

  return context
}

type StepperProps = React.ComponentProps<"div"> & {
  activeStep: number
  orientation?: "horizontal" | "vertical"
}

function Stepper({
  activeStep,
  orientation = "horizontal",
  className,
  children,
  ...props
}: StepperProps) {
  return (
    <StepperContext.Provider value={{ activeStep, orientation }}>
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn("flex flex-col gap-4", className)}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

type StepperItemProps = React.ComponentProps<"div"> & {
  step: number
}

function StepperItem({
  step,
  className,
  children,
  ...props
}: StepperItemProps) {
  const { activeStep, orientation } = useStepper()

  const state: StepState =
    step < activeStep
      ? "completed"
      : step === activeStep
        ? "active"
        : "pending"

  return (
    <StepperItemContext.Provider value={{ step, state }}>
      <div
        data-slot="stepper-item"
        data-step={step}
        data-state={state}
        className={cn(
          "flex flex-row items-center gap-2",
          orientation === "horizontal" && "flex-1",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { step, state } = useStepperItem()

  return (
    <button
      data-slot="stepper-trigger"
      className={cn(
        "inline-flex size-8 shrink-0 items-center justify-center rounded-full border-2 text-sm font-semibold transition-colors",
        "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2",
        "disabled:pointer-events-none disabled:opacity-50",
        state === "completed" &&
          "border-primary bg-primary text-primary-foreground",
        state === "active" &&
          "border-primary bg-primary text-primary-foreground",
        state === "pending" &&
          "border-muted-foreground/40 bg-background text-muted-foreground",
        className
      )}
      {...props}
    >
      {children ?? step}
    </button>
  )
}

function StepperTitle({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-title"
      className={cn("text-sm font-medium", className)}
      {...props}
    />
  )
}

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn("text-xs text-muted-foreground", className)}
      {...props}
    />
  )
}

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = useStepper()
  const { state } = useStepperItem()

  return (
    <div
      data-slot="stepper-separator"
      className={cn(
        "transition-colors",
        orientation === "horizontal" ? "h-px flex-1" : "ml-4 w-px self-stretch",
        state === "completed" ? "bg-primary" : "bg-border",
        className
      )}
      {...props}
    />
  )
}

type StepperContentProps = React.ComponentProps<"div"> & {
  step: number
}

function StepperContent({
  step,
  className,
  children,
  ...props
}: StepperContentProps) {
  const { activeStep } = useStepper()

  if (step !== activeStep) return null

  return (
    <div
      data-slot="stepper-content"
      className={cn("text-sm", className)}
      {...props}
    >
      {children}
    </div>
  )
}

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
}

